G4_KP = {
    'ch4-1': ['亿以内数的认识','亿以内数的读写','数的产生和十进制','亿以上数的认识'],
    'ch4-2': ['口算乘法','三位数乘两位数','因数中间有0的乘法','解决问题：积的变化'],
    'ch4-3': ['平行与垂直','画垂线和平行线','平行四边形','梯形'],
    'ch4-4': ['小数的意义','小数的读写','小数的性质','小数的大小比较'],
    'ch4-5': ['认识条形统计图','一格代表多个单位','数据分析','简单推理'],
}
KP_MAP = {'3': G3_KP, '4': G4_KP}
def esc(s):
    return s.replace("\\","\\\\").replace("'","\\'")
def gen():
    tree = {'3': {}, '4': {}}
    for theme, ch_id, ch_title, episodes in ALL_DATA:
        grade = '3' if ch_id.startswith('ch3') else '4'
        if theme not in tree[grade]:
            tree[grade][theme] = {}
        tree[grade][theme][ch_id] = (ch_title, episodes)
    L = []
    L.append("const gradeStories = {")
    for gi, grade in enumerate(['3', '4']):
        L.append(f"  '{grade}': {{")
        themes = list(tree[grade].keys())
        for ti, theme in enumerate(themes):
            tc = THEMES[theme]
            L.append(f"    '{theme}': {{")
            chapters = tree[grade][theme]
            cids = list(chapters.keys())
            for ci, cid in enumerate(cids):
                cht, eps = chapters[cid]
                kps = KP_MAP[grade][cid]
                L.append(f"      '{cid}': {{")
                L.append(f"        title: '{esc(cht)}',")
                L.append(f"        theme: '{esc(tc['name'])}',")
                L.append(f"        coverGradient: '{tc['gradient']}',")
                L.append(f"        episodes: [")
                for ei, ep in enumerate(eps):
                    et, nv, sc, ki, q = ep
                    kn = kps[ki]
                    L.append("          {")
                    L.append(f"            id: '{grade}-{theme}-{cid}-ep{ei+1}',")
                    L.append(f"            title: '{esc(et)}',")
                    L.append(f"            narrative: '{esc(nv)}',")
                    L.append(f"            knowledge: '{esc(kn)}',")
                    L.append(f"            scene: '{esc(sc)}',")
                    if q is None:
                        L.append("            question: null")
                    else:
                        os_str = ', '.join([f"'{esc(o)}'" for o in q[1]])
                        L.append("            question: {")
                        L.append(f"              text: '{esc(q[0])}',")
                        L.append(f"              options: [{os_str}],")
                        L.append(f"              correct: {q[2]},")
                        L.append(f"              explanation: '{esc(q[3])}'")
                        L.append("            }")
                    cm = ',' if ei < len(eps)-1 else ''
                    L.append(f"          }}{cm}")
                L.append("        ]")
                cm = ',' if ci < len(cids)-1 else ''
                L.append(f"      }}{cm}")
            cm = ',' if ti < len(themes)-1 else ''
            L.append(f"    }}{cm}")
        cm = ',' if gi < 1 else ''
        L.append(f"  }}{cm}")
    L.append("};")
    L.append("")
    L.append("export default gradeStories;")
    with open(OUTPUT, 'w', encoding='utf-8') as f:
        f.write('\n'.join(L))
    print(f"OK: {len(ALL_DATA)} chapters -> {OUTPUT}")
if __name__ == '__main__':
    gen()
